import { Avatar, DetailLink, EmptyState, MetricCard, PageHeading, ProgressBar, SectionCard, StatusBadge } from "@/components/shared";
import { ProgressChart } from "@/components/progress-chart";
import { getDashboardData } from "@/lib/data";
import { requireUser } from "@/lib/auth";
import { formatTanggal, rataNilai } from "@/lib/utils";
import { BookOpenCheck, ClipboardCheck, GraduationCap, HeartHandshake, Plus, Target, TrendingUp, TriangleAlert, UsersRound } from "lucide-react";
import Link from "next/link";

export default async function DashboardPage() {
  const user = await requireUser();
  const data = await getDashboardData(user);
  const isTeacher = user.role === "ustadz";
  const isGuardian = user.role === "wali";
  const chartData = data.recentSubmissions.slice(0, 7).reverse().map((item) => ({ name: formatTanggal(item.date).replace(/\s\d{4}/, ""), nilai: rataNilai(item.fluency, item.tajwid, item.makhraj) }));
  return <><PageHeading eyebrow={isTeacher ? "Ruang Musyrif" : isGuardian ? "Portal Keluarga" : "Ringkasan Pondok"} title={isTeacher ? `Assalamu'alaikum, ${user.name.split(" ")[0]}` : isGuardian ? `Perkembangan amanah Anda` : "Dashboard Mutabaah"} description={isTeacher ? "Pantau setoran, muraja'ah, dan kebutuhan pendampingan halaqah Anda hari ini." : isGuardian ? "Lihat ringkasan perkembangan hafalan anak dan catatan dari ustadz." : "Gambaran hafalan santri, aktivitas hari ini, dan tindak lanjut yang perlu diperhatikan."} action={isTeacher ? <Link href="/setoran" className="inline-flex items-center justify-center gap-2 rounded-xl bg-emerald-900 px-4 py-3 text-sm font-bold text-white transition hover:bg-emerald-800"><Plus size={17}/>Input Setoran</Link> : isGuardian ? <Link href="/portal-wali" className="inline-flex items-center justify-center gap-2 rounded-xl bg-emerald-900 px-4 py-3 text-sm font-bold text-white transition hover:bg-emerald-800"><HeartHandshake size={17}/>Buka Portal Wali</Link> : <Link href="/master-data" className="inline-flex items-center justify-center gap-2 rounded-xl bg-emerald-900 px-4 py-3 text-sm font-bold text-white transition hover:bg-emerald-800"><Plus size={17}/>Kelola Data</Link>}/><div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4"><MetricCard label={isGuardian ? "Anak terhubung" : isTeacher ? "Santri binaan" : "Santri aktif"} value={data.stats.studentCount} note={isGuardian ? "terhubung ke akun wali" : isTeacher ? "dalam halaqah Anda" : "tercatat pada sistem"} icon={UsersRound}/><MetricCard label="Setoran hari ini" value={data.stats.todayCount} note="telah masuk dan dinilai" icon={ClipboardCheck} tone="sky"/><MetricCard label="Perlu setoran" value={data.stats.pendingCount} note="belum tercatat hari ini" icon={Target} tone="gold"/><MetricCard label="Rata-rata nilai" value={data.stats.averageScore ? data.stats.averageScore : "—"} note="akumulasi setoran tersedia" icon={TrendingUp} tone={data.stats.averageScore >= 85 ? "emerald" : "rose"}/></div><div className="mt-5 grid gap-5 xl:grid-cols-[1.55fr_.95fr]"><SectionCard title="Tren nilai setoran" subtitle="Nilai rata-rata kelancaran, tajwid, dan makhraj pada setoran terakhir" action={<DetailLink href="/progress">Lihat progress</DetailLink>}>{chartData.length ? <div className="px-3 pb-3 pt-4"><ProgressChart data={chartData}/></div> : <EmptyState title="Belum ada grafik" description="Grafik akan tampil setelah setoran dicatat."/>}</SectionCard><SectionCard title="Muraja'ah perlu ditindaklanjuti" subtitle="Jadwal hari ini dan yang sudah melewati jadwal" action={<DetailLink href="/murajaah">Lihat semua</DetailLink>}><div className="divide-y divide-slate-100">{data.dueToday.length ? data.dueToday.map((item) => <div className="flex items-center gap-3 px-5 py-3.5" key={item.id}><span className="grid size-9 place-items-center rounded-xl bg-amber-50 text-amber-700"><BookOpenCheck size={18}/></span><div className="min-w-0 flex-1"><p className="truncate text-sm font-bold text-slate-800">{item.studentName}</p><p className="truncate text-xs text-slate-500">{item.surah ?? "Hafalan terdahulu"} {item.verseStart ? `ayat ${item.verseStart}–${item.verseEnd}` : ""}</p></div><span className="text-[11px] font-bold text-amber-700">{item.dueDate === new Date().toISOString().slice(0, 10) ? "Hari ini" : "Terlewat"}</span></div>) : <EmptyState title="Alhamdulillah, kosong" description="Tidak ada muraja'ah yang perlu ditindaklanjuti saat ini."/>}</div></SectionCard></div><div className="mt-5 grid gap-5 xl:grid-cols-[1.55fr_.95fr]"><SectionCard title="Setoran terbaru" subtitle="Aktivitas hafalan yang terakhir dicatat" action={<DetailLink href="/setoran">Input setoran</DetailLink>}><div className="overflow-x-auto"><table className="w-full min-w-[600px] text-left"><thead><tr className="border-b border-slate-100 text-[10px] uppercase tracking-wider text-slate-400"><th className="px-5 py-3 font-bold">Santri</th><th className="px-3 py-3 font-bold">Setoran</th><th className="px-3 py-3 font-bold">Nilai</th><th className="px-3 py-3 font-bold">Status</th><th className="px-5 py-3 font-bold">Tanggal</th></tr></thead><tbody>{data.recentSubmissions.map((item) => <tr key={item.id} className="border-b border-slate-50 last:border-0"><td className="px-5 py-3.5"><div className="flex items-center gap-2.5"><Avatar name={item.studentName ?? "Santri"} className="size-8"/><span className="font-semibold text-slate-700">{item.studentName}</span></div></td><td className="px-3 py-3.5"><p className="text-sm font-semibold text-slate-700">{item.surah} {item.verseStart}–{item.verseEnd}</p><p className="mt-0.5 text-[11px] text-slate-400">{item.type.replaceAll("_", " ")}</p></td><td className="px-3 py-3.5 text-sm font-bold text-emerald-700">{rataNilai(item.fluency, item.tajwid, item.makhraj)}</td><td className="px-3 py-3.5"><StatusBadge value={item.status}/></td><td className="px-5 py-3.5 text-xs text-slate-500">{formatTanggal(item.date)}</td></tr>)}{!data.recentSubmissions.length && <tr><td colSpan={5}><EmptyState title="Belum ada setoran" description="Mulai pencatatan hafalan dari menu Input Setoran."/></td></tr>}</tbody></table></div></SectionCard><SectionCard title="Butuh perhatian" subtitle="Santri dengan setoran belum lulus atau belum tercatat"><div className="divide-y divide-slate-100">{data.attentionStudents.length ? data.attentionStudents.map((student) => <Link href={`/santri/${student.id}`} key={student.id} className="flex items-center gap-3 px-5 py-3.5 transition hover:bg-slate-50"><Avatar name={student.name} className="bg-rose-500"/><div className="min-w-0 flex-1"><p className="truncate text-sm font-bold text-slate-800">{student.name}</p><p className="truncate text-xs text-slate-500">{student.halaqahName ?? "Belum ada halaqah"}</p></div><TriangleAlert size={17} className="text-amber-500"/></Link>) : <EmptyState title="Semua terkendali" description="Tidak ada santri yang masuk daftar perhatian."/>}</div></SectionCard></div></>;
}
